// Callback Page - Handles the OAuth redirect
function CallbackPage({ navigate }) {
  const { handleCallback, isAuthenticated, error, loading } = useAuth();
  const [processed, setProcessed] = useState(false);

  useEffect(() => {
    if (!processed) {
      handleCallback();
      setProcessed(true);
    }
  }, [handleCallback, processed]);

  useEffect(() => {
    if (processed && isAuthenticated && !loading) {
      const timer = setTimeout(() => navigate('/dashboard'), 1500);
      return () => clearTimeout(timer);
    }
  }, [processed, isAuthenticated, loading, navigate]);

  if (!processed || loading) {
    return (
      <div style={styles.card}>
        <div style={styles.loadingSpinner}>
          <span>⏳ Processing authentication...</span>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div style={styles.card}>
        <h2 style={styles.title}>Authentication Failed</h2>
        <p style={{ color: '#E53E3E', marginBottom: '16px' }}>{error}</p>
        <button
          style={{ ...styles.button, ...styles.primaryButton }}
          onClick={() => navigate('/')}
        >
          Go Home
        </button>
      </div>
    );
  }

  if (isAuthenticated) {
    return (
      <div style={styles.card}>
        <div style={{ textAlign: 'center', padding: '32px' }}>
          <div style={{ fontSize: '48px', marginBottom: '16px' }}>✅</div>
          <h2 style={styles.title}>Authentication Successful!</h2>
          <p style={styles.subtitle}>
            Redirecting to dashboard...
          </p>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.card}>
      <h2 style={styles.title}>Something went wrong</h2>
      <p style={styles.subtitle}>No token was found. Please try again.</p>
      <button
        style={{ ...styles.button, ...styles.primaryButton }}
        onClick={() => navigate('/')}
      >
        Go Home
      </button>
    </div>
  );
}

// Dashboard Page
function DashboardPage({ navigate }) {
  const { token, isAuthenticated, login, fetchWithAuth } = useAuth();
  const [apiResult, setApiResult] = useState(null);
  const [apiLoading, setApiLoading] = useState(false);
  const [showToken, setShowToken] = useState(false);

  if (!isAuthenticated) {
    return (
      <div style={styles.card}>
        <h2 style={styles.title}>Dashboard</h2>
        <p style={styles.subtitle}>You need to be authenticated to view this page.</p>
        <button
          style={{ ...styles.button, ...styles.primaryButton }}
          onClick={login}
        >
          Sign In
        </button>
      </div>
    );
  }

  const handleTestApiCall = async () => {
    setApiLoading(true);
    setApiResult(null);
    try {
      // Replace with your actual API endpoint
      const response = await fetchWithAuth('https://jsonplaceholder.typicode.com/users/1');
      const data = await response.json();
      setApiResult({ success: true, data });
    } catch (err) {
      setApiResult({ success: false, error: err.message });
    } finally {
      setApiLoading(false);
    }
  };

  const getTimeUntilExpiry = () => {
    if (!token.expiresAt) return 'Unknown';
    const remaining = token.expiresAt - Date.now();
    if (remaining <= 0) return 'Expired';
    const minutes = Math.floor(remaining / 60000);
    const seconds = Math.floor((remaining % 60000) / 1000);
    return `${minutes}m ${seconds}s`;
  };

  return (
    <>
      <div style={styles.card}>
        <h2 style={styles.title}>Dashboard</h2>
        <p style={styles.subtitle}>
          You are authenticated. Here's your token information.
        </p>

        <div style={styles.infoRow}>
          <span style={styles.infoLabel}>Token Type</span>
          <span style={styles.infoValue}>{token.tokenType}</span>
        </div>
        <div style={styles.infoRow}>
          <span style={styles.infoLabel}>Scope</span>
          <span style={styles.infoValue}>{token.scope || 'N/A'}</span>
        </div>
        <div style={styles.infoRow}>
          <span style={styles.infoLabel}>Expires At</span>
          <span style={styles.infoValue}>
            {token.expiresAt
              ? new Date(token.expiresAt).toLocaleString()
              : 'Unknown'}
          </span>
        </div>
        <div style={styles.infoRow}>
          <span style={styles.infoLabel}>Time Remaining</span>
          <span style={styles.infoValue}>{getTimeUntilExpiry()}</span>
        </div>
        <div style={{ ...styles.infoRow, borderBottom: 'none' }}>
          <span style={styles.infoLabel}>Access Token</span>
          <button
            style={{ ...styles.button, ...styles.secondaryButton, padding: '4px 12px', fontSize: '12px' }}
            onClick={() => setShowToken(!showToken)}
          >
            {showToken ? 'Hide' : 'Show'}
          </button>
        </div>
        {showToken && (
          <div style={styles.tokenDisplay}>
            {token.accessToken}
          </div>
        )}
      </div>

      <div style={styles.card}>
        <h3 style={{ ...styles.title, fontSize: '20px' }}>Test API Call</h3>
        <p style={styles.subtitle}>
          Make an authenticated API call using the access token in the Authorization header.
        </p>
        <button
          style={{ ...styles.button, ...styles.primaryButton }}
          onClick={handleTestApiCall}
          disabled={apiLoading}
        >
          {apiLoading ? '⏳ Loading...' : '🌐 Make API Call'}
        </button>

        {apiResult && (
          <div style={styles.apiSection}>
            <h4 style={{ marginBottom: '8px', color: apiResult.success ? '#38A169' : '#E53E3E' }}>
              {apiResult.success ? '✅ Success' : '❌ Error'}
            </h4>
            <div style={styles.apiResult}>
              {JSON.stringify(apiResult.success ? apiResult.data : apiResult.error, null, 2)}
            </div>
          </div>
        )}
      </div>
    </>
  );
}

